// ==================== HSDK 补丁 ====================
(function() {
    if (typeof HSDK === 'undefined') {
        window.HSDK = {
            onLogin: function(data) {
                setTimeout(function() {
                    if (data && data.listener) data.listener({ userSdk: { isNewUser: false } });
                }, 1000);
            },
            reportLoginState: function() {},
            onAddictionQuit: function() {},
            getGsSetting: function() { return {}; },
            isRunInApp: function() { return false; },
            openCustomerService: function() {},
            init: function(config, callback) { if (callback && callback.success) callback.success({}); },
            getAccountInfo: function(callback) { if (callback && callback.success) callback.success({}); },
            getLaunchOptionsSync: function() { return {}; },
            triggerGC: function() {},
            exitMiniProgram: function() {},
            navigateToMiniProgram: function() {},
            getSystemInfoSync: function() { return { platform: 'web' }; },
            showModal: function(options) { if (options && options.success) options.success({ confirm: true }); },
            showToast: function() {},
            hideToast: function() {},
            showLoading: function() {},
            hideLoading: function() {},
            setClipboardData: function() {},
            getClipboardData: function(options) { if (options && options.success) options.success({ data: '' }); },
            createRewardedVideoAd: function() {
                return {
                    load: function() { return Promise.resolve(); },
                    show: function() { return Promise.resolve(); },
                    onLoad: function() {}, onError: function() {}, onClose: function() {},
                    offLoad: function() {}, offError: function() {}, offClose: function() {}, destroy: function() {}
                };
            },
            reportBehavior: function() {},
            reportEvent: function() {},
            reportLogin: function() {},
            reportPayment: function() {},
            login: function() { return Promise.resolve(); },
            logout: function() { return Promise.resolve(); },
            pay: function() { return Promise.resolve(); },
            getUserInfo: function() { return Promise.resolve(); },
            onLoginSuccess: function() {},
            onLoginFailed: function() {},
            onPaySuccess: function() {}
        };
    } else {
        var methods = ['init','login','logout','pay','getUserInfo','onLoginSuccess','onLoginFailed',
            'onPaySuccess','onAddictionQuit','reportLoginState','getGsSetting','isRunInApp',
            'openCustomerService','getAccountInfo','getLaunchOptionsSync','triggerGC',
            'exitMiniProgram','navigateToMiniProgram','getSystemInfoSync','showModal',
            'showToast','hideToast','showLoading','hideLoading','setClipboardData',
            'getClipboardData','createRewardedVideoAd','reportBehavior','reportEvent',
            'reportLogin','reportPayment'];
        methods.forEach(function(m) {
            if (typeof HSDK[m] !== 'function') HSDK[m] = function() {};
        });
    }
})();
